SELECT COUNT(DISTINCT commongovernment13.agname) AS ctdagnameok,   COUNT(DISTINCT commongovernment13.bureauname) AS ctdbureaunameok,   COUNT(DISTINCT commongovernment13.coname) AS ctdconameok,   COUNT(DISTINCT commongovernment13.fundingagencyname) AS ctdfundingagencynameok,   COUNT(DISTINCT commongovernment13.naicscode) AS ctdnaicscodeok,   COUNT(DISTINCT commongovernment13.prodorservcode) AS ctdprodorservcodeok,   COUNT(DISTINCT commongovernment13.refidvidpiid) AS ctdrefidvidpiidok,   SUM(CAST(commongovernment13.number_of_records AS BIGINT)) AS sumnumberofrecordsok,   SUM(commongovernment13.obligatedamount) AS sumobligatedamountok FROM commongovernment13 HAVING (COUNT(1) > 0);
